class Solution:
    def canCross(self, stones: List[int]) -> bool:
        pos = {s: i for i, s in enumerate(stones)}
        n = len(stones)
        dp = [set() for _ in range(n)]
        dp[0].add(0)
        for i in range(n):
            for k in dp[i]:
                for nk in (k-1, k, k+1):
                    if nk <= 0: continue
                    j = stones[i] + nk
                    if j in pos:
                        dp[pos[j]].add(nk)
        return bool(dp[n-1])

